import{_ as o,o as e,c as r,ag as i}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Cherry Studio 配置","description":"","frontmatter":{},"headers":[],"relativePath":"tools/cherry-studio.md","filePath":"tools/cherry-studio.md"}'),t={name:"tools/cherry-studio.md"};function l(d,a,h,n,s,u){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="cherry-studio-配置" tabindex="-1">Cherry Studio 配置 <a class="header-anchor" href="#cherry-studio-配置" aria-label="Permalink to &quot;Cherry Studio 配置&quot;">​</a></h1><p>Cherry Studio 是一个跨平台桌面应用，提供 AI 对话和代码生成功能。</p><h2 id="这是什么工具" tabindex="-1">这是什么工具 <a class="header-anchor" href="#这是什么工具" aria-label="Permalink to &quot;这是什么工具&quot;">​</a></h2><p>Cherry Studio 是一个桌面应用，支持 Windows、macOS 和 Linux。它支持多种 AI Provider。</p><h2 id="配置前需要准备什么" tabindex="-1">配置前需要准备什么 <a class="header-anchor" href="#配置前需要准备什么" aria-label="Permalink to &quot;配置前需要准备什么&quot;">​</a></h2><ul><li>有效的 API Key</li><li>默认 Base URL：<code>https://api.1010101.asia/</code></li></ul><h2 id="从哪里打开配置入口" tabindex="-1">从哪里打开配置入口 <a class="header-anchor" href="#从哪里打开配置入口" aria-label="Permalink to &quot;从哪里打开配置入口&quot;">​</a></h2><ol><li>打开 Cherry Studio 应用</li><li>点击左下角的设置图标（齿轮）</li><li>进入&quot;Provider&quot;或&quot;API 设置&quot;页面</li></ol><h2 id="最短完整配置步骤" tabindex="-1">最短完整配置步骤 <a class="header-anchor" href="#最短完整配置步骤" aria-label="Permalink to &quot;最短完整配置步骤&quot;">​</a></h2><ol><li>在设置页面中，点击&quot;添加 Provider&quot;或选择已有 Provider</li><li>选择 Provider 类型为&quot;OpenAI Compatible&quot;或&quot;Custom&quot;</li><li>在 <code>API Key</code> 字段中输入你的 API Key</li><li>在 <code>Base URL</code> 或 <code>API Endpoint</code> 字段中输入：<code>https://api.1010101.asia/</code></li><li>如需填写模型名，输入模型 ID（如 <code>gpt-4</code>）</li><li>点击&quot;保存&quot;或&quot;确认&quot;</li></ol><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="provider-设置" tabindex="-1">Provider 设置 <a class="header-anchor" href="#provider-设置" aria-label="Permalink to &quot;Provider 设置&quot;">​</a></h3><ul><li><strong>Provider 类型</strong>: OpenAI Compatible 或 Custom</li><li><strong>API Key</strong>: <code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code></li><li><strong>Base URL</strong>: <code>https://api.1010101.asia/</code></li><li><strong>Model</strong>: <code>gpt-4</code>（如需要）</li></ul><h2 id="如何验证生效" tabindex="-1">如何验证生效 <a class="header-anchor" href="#如何验证生效" aria-label="Permalink to &quot;如何验证生效&quot;">​</a></h2><ol><li>返回主界面</li><li>发送一个简单问题</li><li>如果收到正常回复，说明配置成功</li></ol><p>或：</p><ol><li>在设置页面中点击&quot;测试连接&quot;按钮</li><li>如果显示&quot;连接成功&quot;，说明配置正确</li></ol><h2 id="常见报错与排查" tabindex="-1">常见报错与排查 <a class="header-anchor" href="#常见报错与排查" aria-label="Permalink to &quot;常见报错与排查&quot;">​</a></h2><h3 id="_401-unauthorized" tabindex="-1">401 Unauthorized <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;401 Unauthorized&quot;">​</a></h3><p><strong>原因</strong>：API Key 错误或无效</p><p><strong>排查</strong>：</p><ul><li>检查 API Key 是否正确</li><li>检查 API Key 是否有多余空格</li><li>确认 API Key 是否已过期或被撤销</li></ul><h3 id="_404-not-found" tabindex="-1">404 Not Found <a class="header-anchor" href="#_404-not-found" aria-label="Permalink to &quot;404 Not Found&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>确认 Base URL 格式符合要求</li><li>检查网络连接是否正常</li></ul><h3 id="模型列表为空" tabindex="-1">模型列表为空 <a class="header-anchor" href="#模型列表为空" aria-label="Permalink to &quot;模型列表为空&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误或服务商不支持模型列表查询</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>手动输入模型名</li></ul><h3 id="连接超时" tabindex="-1">连接超时 <a class="header-anchor" href="#连接超时" aria-label="Permalink to &quot;连接超时&quot;">​</a></h3><p><strong>原因</strong>：网络问题或 Base URL 不可达</p><p><strong>排查</strong>：</p><ul><li>检查网络连接</li><li>确认 Base URL 可以访问</li><li>尝试在浏览器中访问 Base URL</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="provider-类型" tabindex="-1">Provider 类型 <a class="header-anchor" href="#provider-类型" aria-label="Permalink to &quot;Provider 类型&quot;">​</a></h3><p>Cherry Studio 支持多种 Provider 类型。选择&quot;OpenAI Compatible&quot;或&quot;Custom&quot;以使用自定义 Base URL。</p><h3 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h3><p>某些 Provider 可能要求选择模型。请根据服务商文档确认正确的模型名。</p><h3 id="应用重启" tabindex="-1">应用重启 <a class="header-anchor" href="#应用重启" aria-label="Permalink to &quot;应用重启&quot;">​</a></h3><p>修改配置后，某些情况下需要重启 Cherry Studio 才能生效。</p><h3 id="平台差异" tabindex="-1">平台差异 <a class="header-anchor" href="#平台差异" aria-label="Permalink to &quot;平台差异&quot;">​</a></h3><p>Cherry Studio 在不同平台上的界面可能略有不同，但配置流程基本一致。</p>',43)])])}const q=o(t,[["render",l]]);export{p as __pageData,q as default};
